import { task, wait } from "@trigger.dev/sdk/v3";

const trial_id = "human_in_the_loop_approval__f3DZ5Xu";

export const approvalTask = task({
  id: `approvalTask-${trial_id}`,
  run: async () => {
    // Log "Requesting approval..."
    console.log("Requesting approval...");

    // Create a wait token with 1 hour timeout
    const token = await wait.createToken({
      timeout: "1h",
    });

    // Log the token ID
    console.log(`Token ID: ${token.id}`);

    // Wait for the token
    const result = await wait.forToken(token.id);

    // Check if approved
    if (result.approved === true) {
      console.log("Request approved!");
    } else {
      console.log("Request rejected.");
    }
  },
});

